import { Radio as RadioPrimitive } from '@base-ui/react/radio';
import { RadioGroup as RadioGroupPrimitive } from '@base-ui/react/radio-group';
import { clsx } from 'clsx';
import { forwardRef, type ComponentProps, type ComponentRef } from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Radio.module.css';

type RadioSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type RadioProps = RadioPrimitive.Root.Props & { size?: RadioSize };

const Radio = forwardRef<ComponentRef<typeof RadioPrimitive.Root>, RadioProps>(function Radio(
  { className, size = 'md', children, ...props },
  ref,
) {
  return (
    <RadioPrimitive.Root
      ref={ref}
      data-slot="radio-root"
      data-size={size}
      className={mergeClassName(className, styles.radio)}
      {...props}
    >
      {children ?? <RadioIndicator />}
    </RadioPrimitive.Root>
  );
});

function RadioIndicator({ className, children, ...props }: RadioPrimitive.Indicator.Props) {
  return (
    <RadioPrimitive.Indicator
      data-slot="radio-indicator"
      className={mergeClassName(className, styles.indicator)}
      {...props}
    >
      {children ?? <RadioIndicatorIcon />}
    </RadioPrimitive.Indicator>
  );
}

function RadioIndicatorIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      aria-hidden="true"
      data-slot="radio-indicator-icon"
      className={clsx(styles.icon, className)}
      {...props}
    />
  );
}

function RadioField({ className, ...props }: ComponentProps<'label'>) {
  return <label data-slot="radio-field" className={clsx(styles.field, className)} {...props} />;
}

function RadioLabel({ className, ...props }: ComponentProps<'span'>) {
  return <span data-slot="radio-label" className={clsx(styles.label, className)} {...props} />;
}

function RadioGroup({ className, ...props }: RadioGroupPrimitive.Props) {
  return (
    <RadioGroupPrimitive
      data-slot="radio-group-root"
      className={mergeClassName(className, styles.group)}
      {...props}
    />
  );
}

function RadioGroupLabel({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div data-slot="radio-group-label" className={clsx(styles.groupLabel, className)} {...props} />
  );
}

function RadioGroupList({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div data-slot="radio-group-list" className={clsx(styles.groupList, className)} {...props} />
  );
}

export {
  Radio,
  RadioIndicator,
  RadioIndicatorIcon,
  RadioField,
  RadioLabel,
  RadioGroup,
  RadioGroupLabel,
  RadioGroupList,
};

@layer ui.components {
  .field {
    display: inline-flex;
    align-items: center;
    gap: var(--radio-gap, var(--spacing-2));
    vertical-align: middle;
    cursor: pointer;

    &:has(.radio[data-disabled], .radio[data-readonly]) {
      cursor: default;
    }
  }

  .radio {
    box-sizing: border-box;
    display: inline-flex;
    flex: none;
    align-items: center;
    justify-content: center;
    -webkit-appearance: none;
    appearance: none;
    width: var(--_radio-size, 1.25rem);
    height: var(--_radio-size, 1.25rem);
    margin: 0;
    border: var(--radio-border-width, var(--border-width-sm)) solid
      var(--radio-border-color, var(--color-border));
    border-radius: var(--radius-full);
    padding: 0;
    background-color: var(--radio-bg, var(--color-background));
    color: var(--radio-indicator-color, var(--color-primary-foreground));
    outline: 0;
    line-height: 0;
    user-select: none;
    cursor: pointer;
    transition:
      background-color var(--radio-transition, var(--transition-default)),
      border-color var(--radio-transition, var(--transition-default)),
      color var(--radio-transition, var(--transition-default)),
      opacity var(--radio-transition, var(--transition-default));

    &[data-checked] {
      border-color: var(--radio-border-color-checked, var(--color-primary));
      background-color: var(--radio-bg-checked, var(--color-primary));
    }

    &:focus-visible {
      outline: var(--radio-focus-ring-width, var(--border-width-sm)) solid
        var(--radio-focus-ring-color, var(--color-ring));
      outline-offset: var(--radio-focus-ring-offset, var(--border-width-sm));
    }

    @media (hover: hover) {
      &[data-unchecked]:not([data-readonly]):hover {
        background-color: var(--radio-bg-hover, var(--color-accent));
      }
    }

    &[data-readonly],
    &[data-disabled] {
      cursor: default;
    }

    &[data-disabled] {
      opacity: var(--radio-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }
    &[data-size='xs'] {
      --_radio-size: var(--radio-size-xs, 0.875rem);
      --_radio-indicator-size: var(--radio-indicator-size-xs, 0.25rem);
    }

    &[data-size='sm'] {
      --_radio-size: var(--radio-size-sm, 1rem);
      --_radio-indicator-size: var(--radio-indicator-size-sm, 0.375rem);
    }

    &[data-size='md'] {
      --_radio-size: var(--radio-size-md, 1.25rem);
      --_radio-indicator-size: var(--radio-indicator-size-md, 0.5rem);
    }

    &[data-size='lg'] {
      --_radio-size: var(--radio-size-lg, 1.5rem);
      --_radio-indicator-size: var(--radio-indicator-size-lg, 0.625rem);
    }

    &[data-size='xl'] {
      --_radio-size: var(--radio-size-xl, 1.75rem);
      --_radio-indicator-size: var(--radio-indicator-size-xl, 0.75rem);
    }
  }

  .indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    height: 100%;

    &[data-unchecked] {
      display: none;
    }
  }

  .icon {
    display: block;
    width: var(--_radio-indicator-size, 0.5rem);
    height: var(--_radio-indicator-size, 0.5rem);
    border: var(--radio-indicator-border-width, 0) solid
      var(--radio-indicator-border-color, currentColor);
    border-radius: var(--radio-indicator-radius, var(--radius-full));
    background-color: currentColor;
  }

  .label {
    color: var(--radio-label-color, var(--color-foreground));
    font-size: var(--radio-label-font-size, var(--text-sm));
    font-weight: var(--radio-label-font-weight, var(--weight-medium));
    line-height: var(--radio-label-line-height, var(--line-height-text-sm));
  }

  .group {
    display: flex;
    flex-direction: column;
    gap: var(--radio-group-gap, var(--spacing-2));
    color: var(--radio-group-color, var(--color-foreground));
  }

  .groupLabel {
    color: var(--radio-group-label-color, var(--radio-group-color, var(--color-foreground)));
    font-size: var(--radio-group-label-font-size, var(--text-sm));
    font-weight: var(--radio-group-label-font-weight, var(--weight-semibold));
    line-height: var(--radio-group-label-line-height, var(--line-height-text-sm));
  }

  .groupList {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    gap: var(--radio-group-list-gap, var(--spacing-2));
  }
}

export {
  Radio,
  RadioIndicator,
  RadioIndicatorIcon,
  RadioField,
  RadioLabel,
  RadioGroup,
  RadioGroupLabel,
  RadioGroupList,
} from './Radio';
